package org.apache.commons.csv;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

class CSVFormatTest {

    @Mock
    private Reader mockReader;

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParseReturnsCSVParserInstance() throws IOException {
        CSVParser parser = csvFormat.parse(mockReader);
        assertNotNull(parser);
        assertEquals(mockReader, parser.getReader());
        assertEquals(csvFormat, parser.getFormat());
    }

    @Test
    void testParseWithNullReaderThrowsException() {
        assertThrows(NullPointerException.class, () -> csvFormat.parse(null));
    }

    @Test
    void testParseWithCustomFormat() throws IOException {
        CSVFormat customFormat = CSVFormat.newFormat(';')
                .withQuoteChar('\'')
                .withIgnoreEmptyLines(false)
                .withRecordSeparator("\n");
        CSVParser parser = customFormat.parse(mockReader);
        assertNotNull(parser);
        assertEquals(mockReader, parser.getReader());
        assertEquals(customFormat, parser.getFormat());
    }
}
